mapper.select:
SELECT
    t1.agent_id as agentId,
    t2.venue_type as venueType,
    sum(t2.valid_amount) as validAmount,
    max(t1.rebate_amount) as commissionAmount,
    max(t1.adjust_amount) as adjustAmount,
    max(t1.rebate_adjust_amount) as rebateAdjustAmount
FROM
`agent_rebate_final_report` t1,
agent_rebate_report_detail t2
WHERE t1.id = t2.rebate_report_id
AND t1.id in (
    select report_id from agent_commission_review_record t3
    where t1.id = t3.report_id

    AND t3.commission_type = #{vo.commissionType}


    and t3.order_status IN

        #{value}


)
AND t1.site_code = #{vo.siteCode}

    and t1.agent_id IN

        #{value}




    AND t1.agent_account = #{vo.agentAccount}


    AND t1.end_time  >=  #{vo.startTime}


    AND t1.start_time  <=  #{vo.endTime}

group by t1.agent_id, t2.venue_type

SELECT
t1.agent_id as agentId,
sum(t1.new_valid_number) as newActiveNumber,
sum(t1.new_user_amount) as commissionAmount,
sum(t2.adjust_commission_amount) as reviewAdjustAmount
FROM
`agent_rebate_final_report` t1,
agent_commission_review_record t2
WHERE t1.id = t2.report_id
AND t1.site_code = #{vo.siteCode}

    and t1.agent_id IN

        #{value}



    and t2.order_status IN

        #{value}



    AND t1.agent_id = #{vo.agentId}


    AND t2.commission_type = #{vo.commissionType}


    AND t1.end_time  >=  #{vo.startTime}


    AND t1.start_time  <=  #{vo.endTime}

group by t1.agent_id
